INSERT INTO `v1_28fa45b0e9f80c9cb7c3f952d4c431c1b6d40fa71d2152522737277a162ce5f7` VALUES (1007405034, 0, 1, 0.5, 0, 11, 6, "あら。\nこないだぷりぷりして帰った件は\n綺麗さっぱりなかったことにするのね。\nオーケイ、了解よ。", 117531, 1007405, 0);
INSERT INTO `v1_28fa45b0e9f80c9cb7c3f952d4c431c1b6d40fa71d2152522737277a162ce5f7` VALUES (1007405035, "", "", "", "", 91, "", "", 0, 1007405, "");
