INSERT INTO `v1_28fa45b0e9f80c9cb7c3f952d4c431c1b6d40fa71d2152522737277a162ce5f7` VALUES (1007413076, "", "", "", "", 103, 0, 1007413127, "頭痛に効くツボを押すわね。", 1007413, "");
